CREATE OR REPLACE FUNCTION fpb_kromss_get_ppm_des (ai_year integer ,ai_month integer, as_memno char) RETURNS timestamp(0) AS $body$
DECLARE

ldtm_date sc_com_m_receipt.receipt_date%type;
ls_date  varchar(500);

BEGIN
  select  coalesce( max(receipt_date),'1/1/1900')
  into STRICT    ldtm_date
  from    sc_com_m_receipt
  where 	ppm_status = '1'
  and 	  month_receive_year = ai_year
  and 	  month_receive_month = ai_month
  and 	  membership_no = as_memno;

  if ldtm_date = '1/1/1900' then
    return null;
  end if;

  RETURN ldtm_date;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
